dashboard.definition:
{
	"title": "Source Detail",
	"description": "Host-level and host/index-level source detail dashboard. Host is required; index can be specific or wildcard.",
	"inputs": {
		"input_global_trp": {
			"options": {
				"defaultValue": "-24h@h,now",
				"token": "global_time"
			},
			"title": "Global Time Range",
			"type": "input.timerange"
		},
		"input_j0JJ7P3r": {
			"options": {
				"defaultValue": "*",
				"token": "selected_index"
			},
			"title": "index",
			"type": "input.text"
		},
		"input_8S2RwJ03": {
			"options": {
				"defaultValue": "*",
				"token": "selected_host"
			},
			"title": "host",
			"type": "input.text"
		},
		"input_YYkhSMo6": {
			"options": {
				"defaultValue": "*",
				"token": "event_keyword"
			},
			"title": "Search in raw",
			"type": "input.text"
		}
	},
	"defaults": {
		"dataSources": {
			"ds.search": {
				"options": {
					"queryParameters": {
						"earliest": "$global_time.earliest$",
						"latest": "$global_time.latest$"
					}
				}
			},
			"ds.spl2": {
				"options": {
					"queryParameters": {
						"earliest": "$global_time.earliest$",
						"latest": "$global_time.latest$"
					}
				}
			}
		},
		"visualizations": {
			"global": {
				"showProgressBar": true
			}
		}
	},
	"visualizations": {
		"viz_3sQpwhHC": {
			"type": "splunk.singlevalue",
			"dataSources": {
				"primary": "ds_f6TGy0WE"
			},
			"title": "Last Known Event single",
			"cornerRadius": [
				20,
				20,
				20,
				20
			]
		},
		"viz_Q8rYsOTy": {
			"type": "splunk.singlevalue",
			"dataSources": {
				"primary": "ds_STyIpOh8"
			},
			"title": "Time Since Last Event single",
			"cornerRadius": [
				20,
				20,
				20,
				20
			]
		},
		"viz_X4FGvkCC": {
			"type": "splunk.table",
			"dataSources": {
				"primary": "ds_LfQwS1i4"
			},
			"title": "Selected Source Summary table",
			"options": {},
			"context": {},
			"containerOptions": {},
			"showProgressBar": true,
			"showLastUpdated": false
		},
		"viz_R70om6Mn": {
			"type": "splunk.singlevalue",
			"dataSources": {
				"primary": "ds_AECTp8oE"
			},
			"title": "First Event in Range",
			"cornerRadius": [
				20,
				20,
				20,
				20
			]
		},
		"viz_0A9PTZko": {
			"type": "splunk.singlevalue",
			"dataSources": {
				"primary": "ds_19mtQl9o"
			},
			"title": "Events in Range",
			"cornerRadius": [
				20,
				20,
				20,
				20
			]
		},
		"viz_wYZE3ulV": {
			"type": "splunk.singlevalue",
			"dataSources": {
				"primary": "ds_WTfTO1Dq"
			},
			"title": "Events 7 Days",
			"cornerRadius": [
				20,
				20,
				20,
				20
			]
		},
		"viz_nAzOYE14": {
			"type": "splunk.column",
			"dataSources": {
				"primary": "ds_Oac4EUhw"
			},
			"title": "Events by Day",
			"containerOptions": {},
			"showProgressBar": true,
			"showLastUpdated": false,
			"options": {},
			"context": {}
		},
		"viz_G9enyLA6": {
			"type": "splunk.table",
			"dataSources": {
				"primary": "ds_zgl4vpxA"
			},
			"title": "Sources and Sourcetypes in Selected Range",
			"description": "Shows source/sourcetype only if events exist in selected time range."
		},
		"viz_xeyrv90H": {
			"type": "splunk.events",
			"dataSources": {
				"primary": "ds_8hBMh5uS"
			},
			"title": "Events",
			"description": "Recent Events in Selected Range"
		},
		"viz_E88H4GYK": {
			"type": "splunk.singlevalue",
			"dataSources": {
				"primary": "ds_WjoIu2U1"
			},
			"title": "Overall Status",
			"eventHandlers": [],
			"cornerRadius": [
				20,
				20,
				20,
				20
			],
			"options": {
				"shouldAbbreviateMajorValue": true
			}
		},
		"viz_ZxDrJBAV": {
			"type": "splunk.table",
			"dataSources": {
				"primary": "ds_L4paPYXc"
			},
			"title": "Source Coverage by Index"
		},
		"viz_d6ivOb0l": {
			"type": "splunk.rectangle",
			"showProgressBar": false,
			"options": {
				"fillColor": "transparent",
				"rx": 20,
				"strokeColor": "#4CAF50",
				"strokeWidth": 4
			},
			"containerOptions": {
				"visibility": {
					"showConditions": [
						"condition_Qm6RYyvK"
					]
				}
			}
		},
		"viz_OFHvIFlC": {
			"type": "splunk.rectangle",
			"showProgressBar": false,
			"options": {
				"fillColor": "transparent",
				"rx": 20,
				"strokeColor": "#FFC107",
				"strokeWidth": 4
			},
			"containerOptions": {
				"visibility": {
					"showConditions": [
						"condition_spp5zsI4"
					]
				}
			}
		},
		"viz_MiOXVQXZ": {
			"type": "splunk.rectangle",
			"showProgressBar": false,
			"options": {
				"fillColor": "transparent",
				"rx": 20,
				"strokeColor": "#EF5350",
				"strokeWidth": 4
			},
			"containerOptions": {
				"visibility": {
					"showConditions": [
						"condition_4BKhkpkW"
					]
				}
			}
		},
		"viz_VyhQZPNV": {
			"type": "splunk.rectangle",
			"showProgressBar": false,
			"options": {
				"fillColor": "transparent",
				"rx": 20,
				"strokeColor": "#4FC3F7",
				"strokeWidth": 4
			},
			"containerOptions": {
				"visibility": {
					"showConditions": [
						"condition_lrzFhwgf"
					]
				}
			}
		},
		"viz_PD1o3LGA": {
			"type": "splunk.rectangle",
			"showProgressBar": false,
			"options": {
				"fillColor": "transparent",
				"rx": 20,
				"strokeColor": "#b175ff",
				"strokeWidth": 4
			}
		}
	},
	"dataSources": {
		"ds_mZZ8Pkmz": {
			"type": "ds.search",
			"options": {
				"query": "| tstats latest(_time) as last_known_event\r\n         earliest(_time) as first_known_event\r\n         count as total_known_events\r\n  where index=$selected_index$ host=$selected_host$ earliest=0 latest=now\r\n  by host index\r\n\r\n| append [\r\n    | inputlookup host_index_alert\r\n    | where enabled=1\r\n    | search host=$selected_host$ index=$selected_index$\r\n    | eval lookup_only=1\r\n    | fields host index work_time non_work_time enabled first_seen last_seen_discovery comment lookup_only\r\n]\r\n\r\n| stats\r\n    max(last_known_event) as last_known_event\r\n    min(first_known_event) as first_known_event\r\n    sum(total_known_events) as total_known_events\r\n    values(work_time) as work_time\r\n    values(non_work_time) as non_work_time\r\n    values(enabled) as enabled\r\n    values(first_seen) as first_seen\r\n    values(last_seen_discovery) as last_seen_discovery\r\n    values(comment) as comment\r\n    max(lookup_only) as lookup_only\r\n  by host index\r\n\r\n| eval work_time=coalesce(tonumber(mvindex(work_time,0)),5)\r\n| eval non_work_time=coalesce(tonumber(mvindex(non_work_time,0)),60)\r\n\r\n| eval current_hour=tonumber(strftime(now(), \"%H\"))\r\n| eval current_wday=tonumber(strftime(now(), \"%w\"))\r\n| eval is_work_hours=if(current_wday>=1 AND current_wday<=5 AND current_hour>=9 AND current_hour<18,1,0)\r\n| eval work_window=if(is_work_hours=1,\"Work time\",\"Non-work time\")\r\n| eval threshold_min=if(is_work_hours=1,work_time,non_work_time)\r\n\r\n| eval minutes_since_last_event=if(isnull(last_known_event),null(),round((now()-last_known_event)/60,0))\r\n| eval over_threshold_min=if(isnull(minutes_since_last_event),null(),max(minutes_since_last_event-threshold_min,0))\r\n\r\n| eval status=case(\r\n    isnull(last_known_event), \"No Data\",\r\n    minutes_since_last_event>1440, \"No Data\",\r\n    minutes_since_last_event<=threshold_min, \"OK\",\r\n    minutes_since_last_event>threshold_min AND minutes_since_last_event<=1440, \"Late\",\r\n    true(), \"Unknown\"\r\n)\r\n\r\n| eval last_known_event_time=if(isnull(last_known_event),\"NO EVENTS\",strftime(last_known_event,\"%Y-%m-%d %H:%M:%S\"))\r\n| eval first_known_event_time=if(isnull(first_known_event),\"NO EVENTS\",strftime(first_known_event,\"%Y-%m-%d %H:%M:%S\"))\r\n\r\n| eval gap_display=case(\r\n    isnull(minutes_since_last_event), \"NO EVENTS\",\r\n    minutes_since_last_event>=60, round(minutes_since_last_event/60,1).\" Hour\",\r\n    true(), minutes_since_last_event.\" min\"\r\n)\r\n\r\n| eval over_display=case(\r\n    isnull(over_threshold_min), \"0 min\",\r\n    over_threshold_min>=60, round(over_threshold_min/60,1).\" Hour\",\r\n    true(), over_threshold_min.\" min\"\r\n)\r\n\r\n| eval threshold_display=case(\r\n    threshold_min>=60, round(threshold_min/60,1).\" Hour\",\r\n    true(), threshold_min.\" min\"\r\n)\r\n\r\n| eval gap_info=case(\r\n    isnull(last_known_event), \"no events found at all\",\r\n    minutes_since_last_event<=threshold_min, \"within threshold / threshold \".threshold_display,\r\n    minutes_since_last_event>threshold_min, \"exceeded by \".over_display.\" / threshold \".threshold_display,\r\n    true(), \"unknown\"\r\n)\r\n\r\n| eval threshold_info=\"work=\".work_time.\" min, non-work=\".non_work_time.\" min\"\r\n\r\n| table host index status last_known_event first_known_event last_known_event_time first_known_event_time total_known_events minutes_since_last_event gap_display threshold_min threshold_display over_threshold_min over_display work_time non_work_time work_window threshold_info gap_info first_seen last_seen_discovery comment"
			},
			"name": "ds_base_source_health"
		},
		"ds_f6TGy0WE": {
			"type": "ds.chain",
			"options": {
				"extend": "ds_mZZ8Pkmz",
				"query": "| stats max(last_known_event) as last_known_event\r\n| eval selected=if(trim(\"$selected_host$\")!=\"*\" OR trim(\"$selected_index$\")!=\"*\",1,0)\r\n| eval value=case(\r\n    selected=0, \"Select host or index\",\r\n    isnull(last_known_event), \"NO EVENTS\",\r\n    true(), strftime(last_known_event,\"%H:%M:%S\")\r\n)\r\n| eval percent_label=case(\r\n    selected=0, \"select host or index\",\r\n    isnull(last_known_event), \"no events found\",\r\n    true(), strftime(last_known_event,\"%Y-%m-%d %H:%M:%S\")\r\n)\r\n| table value percent_label"
			},
			"name": "ds_chain_last_known_event"
		},
		"ds_STyIpOh8": {
			"type": "ds.chain",
			"options": {
				"extend": "ds_mZZ8Pkmz",
				"query": "| stats max(last_known_event) as last_known_event min(threshold_min) as threshold_min\r\n| eval selected=if(trim(\"$selected_host$\")!=\"*\" OR trim(\"$selected_index$\")!=\"*\",1,0)\r\n| eval threshold_min=coalesce(threshold_min,5)\r\n| eval minutes=if(isnull(last_known_event),null(),round((now()-last_known_event)/60,0))\r\n| eval over_min=if(minutes>threshold_min,minutes-threshold_min,0)\r\n\r\n| eval value=case(\r\n    selected=0, \"Select host or index\",\r\n    isnull(minutes), \"NO EVENTS\",\r\n    minutes>=60, round(minutes/60,1).\" Hour\",\r\n    true(), minutes.\" min\"\r\n)\r\n\r\n| eval threshold_fmt=case(\r\n    threshold_min>=60, round(threshold_min/60,1).\" Hour\",\r\n    true(), threshold_min.\" min\"\r\n)\r\n\r\n| eval over_fmt=case(\r\n    over_min>=60, round(over_min/60,1).\" Hour\",\r\n    true(), over_min.\" min\"\r\n)\r\n\r\n| eval percent_label=case(\r\n    selected=0, \"select host or index\",\r\n    isnull(minutes), \"no events found\",\r\n    minutes<=threshold_min, \"within threshold / threshold \".threshold_fmt,\r\n    minutes>threshold_min, \"exceeded by \".over_fmt.\" / threshold \".threshold_fmt,\r\n    true(), \"unknown\"\r\n)\r\n\r\n| table value percent_label"
			},
			"name": "ds_chain_time_since_last"
		},
		"ds_LfQwS1i4": {
			"type": "ds.chain",
			"options": {
				"extend": "ds_mZZ8Pkmz",
				"query": "| eval selected=if(trim(\"$selected_host$\")!=\"*\" OR trim(\"$selected_index$\")!=\"*\",1,0)\r\n| where selected=1\r\n\r\n| table host index status last_known_event_time first_known_event_time total_known_events minutes_since_last_event   work_time non_work_time comment\r\n| sort status -minutes_since_last_event host index\r\n\r\n| appendpipe [\r\n    | stats count as row_count\r\n    | where row_count=0\r\n    | eval host=if(trim(\"$selected_host$\")=\"*\",\"Please select host\",\"$selected_host$\")\r\n    | eval index=if(trim(\"$selected_index$\")=\"*\",\"Please select index\",\"$selected_index$\")\r\n    | eval status=\"SELECT SOURCE\"\r\n    | eval last_known_event_time=0\r\n    | eval first_known_event_time=0\r\n    | eval total_known_events=0\r\n    | eval minutes_since_last_event=0\r\n    | eval threshold_min=0\r\n    | eval over_threshold_min=0\r\n    | eval work_window=0\r\n    | eval work_time=0\r\n    | eval non_work_time=0\r\n    | eval first_seen=0\r\n    | eval last_seen_discovery=0\r\n    | eval comment=\"Select a specific host or index to view source details.\"\r\n    | table host index status last_known_event_time first_known_event_time total_known_events minutes_since_last_event work_time non_work_time  comment\r\n]"
			},
			"name": "ds_chain_selected_source_summary"
		},
		"ds_MMq7F7bO": {
			"type": "ds.search",
			"options": {
				"query": "| makeresults\r\n| eval selected=if(trim(\"$selected_host$\")!=\"*\" OR trim(\"$selected_index$\")!=\"*\",1,0)\r\n| eval events_in_range=0\r\n\r\n| append [\r\n    | tstats count as events_in_range\r\n             earliest(_time) as first_event_in_range\r\n             latest(_time) as last_event_in_range\r\n      where index=$selected_index$ host=$selected_host$ earliest=$global_time.earliest$ latest=$global_time.latest$\r\n]\r\n\r\n| stats\r\n    sum(events_in_range) as events_in_range\r\n    min(first_event_in_range) as first_event_in_range\r\n    max(last_event_in_range) as last_event_in_range\r\n    max(selected) as selected\r\n\r\n| eval events_in_range=coalesce(events_in_range,0)\r\n\r\n| eval first_event_in_range_time=if(isnull(first_event_in_range),\"NO EVENTS\",strftime(first_event_in_range,\"%Y-%m-%d %H:%M:%S\"))\r\n| eval last_event_in_range_time=if(isnull(last_event_in_range),\"NO EVENTS\",strftime(last_event_in_range,\"%Y-%m-%d %H:%M:%S\"))\r\n\r\n| table selected events_in_range first_event_in_range first_event_in_range_time last_event_in_range last_event_in_range_time"
			},
			"name": "ds_base_range_profile"
		},
		"ds_AECTp8oE": {
			"type": "ds.chain",
			"options": {
				"extend": "ds_MMq7F7bO",
				"query": "| eval value=case(\r\n    selected=0, \"Select host or index\",\r\n    isnull(first_event_in_range), \"NO EVENTS\",\r\n    true(), strftime(first_event_in_range,\"%H:%M:%S\")\r\n)\r\n\r\n| eval percent_label=case(\r\n    selected=0, \"select host or index\",\r\n    isnull(first_event_in_range), \"no events in selected range\",\r\n    true(), first_event_in_range_time\r\n)\r\n\r\n| table value percent_label"
			},
			"name": "ds_chain_first_event_range"
		},
		"ds_19mtQl9o": {
			"type": "ds.chain",
			"options": {
				"extend": "ds_MMq7F7bO",
				"query": "| eval value=case(\r\n    selected=0, \"Select host or index\",\r\n    true(), tostring(coalesce(events_in_range,0))\r\n)\r\n\r\n| eval percent_label=case(\r\n    selected=0, \"select host or index\",\r\n    events_in_range=0, \"no events in selected range\",\r\n    true(), \"events in selected time range\"\r\n)\r\n\r\n| table value percent_label"
			},
			"name": "ds_chain_events_range"
		},
		"ds_YissY4WN": {
			"type": "ds.search",
			"options": {
				"query": "| makeresults\r\n| eval host=\"$selected_host$\"\r\n| eval index=\"$selected_index$\"\r\n| eval events_7d=0\r\n| eval selected=if(trim(\"$selected_host$\")!=\"*\" OR trim(\"$selected_index$\")!=\"*\",1,0)\r\n\r\n| append [\r\n    | tstats count as events_7d\r\n      where index=$selected_index$ host=$selected_host$ earliest=-7d@d latest=now\r\n      by host index\r\n    | eval selected=if(trim(\"$selected_host$\")!=\"*\" OR trim(\"$selected_index$\")!=\"*\",1,0)\r\n]\r\n\r\n| stats sum(events_7d) as events_7d max(selected) as selected by host index\r\n| table host index events_7d selected"
			},
			"name": "ds_base_events_7d"
		},
		"ds_WTfTO1Dq": {
			"type": "ds.chain",
			"options": {
				"query": "| stats sum(events_7d) as events_7d max(selected) as selected\r\n| eval value=case(\r\n    selected=0, \"Select host or index\",\r\n    true(), tostring(coalesce(events_7d,0))\r\n)\r\n| eval percent_label=case(\r\n    selected=0, \"select host or index\",\r\n    events_7d=0, \"no events for last 7 days\",\r\n    true(), \"events for last 7 days\"\r\n)\r\n| table value percent_label",
				"extend": "ds_YissY4WN"
			},
			"name": "ds_chain_events_7d"
		},
		"ds_rlEPoeGW": {
			"type": "ds.search",
			"options": {
				"query": "| tstats count as events\r\n  where index=$selected_index$ host=$selected_host$ earliest=$global_time.earliest$ latest=$global_time.latest$\r\n  by _time span=1h\r\n\r\n| eval hour=strftime(_time,\"%Y-%m-%d %H:%M\")\r\n| table hour events\r\n| sort hour"
			},
			"name": "ds_base_events_by_hour"
		},
		"ds_mbPKcZFn": {
			"type": "ds.chain",
			"options": {
				"extend": "ds_rlEPoeGW",
				"query": "| table hour events"
			},
			"name": "Search_1"
		},
		"ds_RfAgWfR9": {
			"type": "ds.search",
			"options": {
				"query": "| tstats count as total_known_events\r\n         latest(_time) as latest_event\r\n         earliest(_time) as first_event\r\n  where index=$selected_index$ host=$selected_host$ earliest=0 latest=now\r\n  by host index source sourcetype\r\n\r\n| eval first_event_time=if(isnull(first_event),\"NO EVENTS\",strftime(first_event,\"%Y-%m-%d %H:%M:%S\"))\r\n| eval latest_event_time=if(isnull(latest_event),\"NO EVENTS\",strftime(latest_event,\"%Y-%m-%d %H:%M:%S\"))\r\n\r\n| table host index source sourcetype total_known_events first_event_time latest_event_time\r\n| sort - total_known_events\r\n\r\n| appendpipe [\r\n    | stats count as row_count\r\n    | where row_count=0\r\n    | eval host=\"$selected_host$\"\r\n    | eval index=\"$selected_index$\"\r\n    | eval source=\"NO KNOWN SOURCE\"\r\n    | eval sourcetype=\"NO KNOWN SOURCETYPE\"\r\n    | eval total_known_events=0\r\n    | eval first_event_time=\"NO EVENTS\"\r\n    | eval latest_event_time=\"No historical events found for selected host/index\"\r\n    | table host index source sourcetype total_known_events first_event_time latest_event_time\r\n]"
			},
			"name": "ds_base_sources_sourcetypes"
		},
		"ds_zgl4vpxA": {
			"type": "ds.chain",
			"options": {
				"query": "| table host index source sourcetype total_known_events first_event_time latest_event_time\r\n| rename\r\n    host as Host\r\n    index as Index\r\n    source as Source\r\n    sourcetype as Sourcetype\r\n    total_known_events as \"Total Known Events\"\r\n    first_event_time as \"First Known Event\"\r\n    latest_event_time as \"Last Known Event\"",
				"extend": "ds_RfAgWfR9"
			},
			"name": "ds_chain_sources_sourcetypes"
		},
		"ds_ug6ZfP1t": {
			"type": "ds.search",
			"options": {
				"query": "search index=$selected_index$ host=$selected_host$ earliest=$global_time.earliest$ latest=$global_time.latest$\r\n| eval event_keyword=trim(\"$event_keyword$\")\r\n\r\n| where event_keyword=\"\"\r\n    OR event_keyword=\"*\"\r\n    OR like(lower(_raw), \"%\".lower(event_keyword).\"%\")\r\n    OR like(lower(source), \"%\".lower(event_keyword).\"%\")\r\n    OR like(lower(sourcetype), \"%\".lower(event_keyword).\"%\")\r\n    OR like(lower(host), \"%\".lower(event_keyword).\"%\")\r\n    OR like(lower(index), \"%\".lower(event_keyword).\"%\")\r\n\r\n| sort 0 - _time\r\n| head 100\r\n\r\n| eval Time=strftime(_time,\"%Y-%m-%d %H:%M:%S\")\r\n| eval RAW=_raw\r\n\r\n| table Time RAW host index sourcetype source"
			},
			"name": "ds_base_events_raw"
		},
		"ds_PCR46ISV": {
			"type": "ds.chain",
			"options": {
				"query": "| where trim(\"$selected_host$\")!=\"*\" OR trim(\"$selected_index$\")!=\"*\"\r\n| table Time RAW host index sourcetype source",
				"extend": "ds_ug6ZfP1t"
			},
			"name": "ds_chain_events_table"
		},
		"ds_8hBMh5uS": {
			"type": "ds.search",
			"options": {
				"query": "search index=$selected_index$ host=$selected_host$ earliest=$global_time.earliest$ latest=$global_time.latest$\r\n| eval event_keyword=trim(\"$event_keyword$\")\r\n\r\n| where event_keyword=\"\"\r\n    OR event_keyword=\"*\"\r\n    OR like(lower(_raw), \"%\".lower(event_keyword).\"%\")\r\n\r\n| sort 0 - _time\r\n| head 100\r\n\r\n| eval Time=strftime(_time,\"%Y-%m-%d %H:%M:%S\")\r\n| eval Event=_raw\r\n| table Time Event host index sourcetype source\r\n\r\n| appendpipe [\r\n    | stats count as row_count\r\n    | where row_count=0\r\n    | eval Time=\"NO EVENTS\"\r\n    | eval Event=\"No events found for selected host/index/time range or keyword\"\r\n    | eval host=\"$selected_host$\"\r\n    | eval index=\"$selected_index$\"\r\n    | eval sourcetype=\"-\"\r\n    | eval source=\"-\"\r\n    | table Time Event host index sourcetype source\r\n]"
			},
			"name": "Search_2"
		},
		"ds_WjoIu2U1": {
			"type": "ds.chain",
			"options": {
				"extend": "ds_mZZ8Pkmz",
				"query": "| eval input_selected=if(trim(\"$selected_host$\")!=\"*\" OR trim(\"$selected_index$\")!=\"*\",1,0)\r\n\r\n| eval status_priority=case(\r\n    status=\"No Data\", 3,\r\n    status=\"Late\", 2,\r\n    status=\"OK\", 1,\r\n    true(), 0\r\n)\r\n\r\n| stats max(status_priority) as status_priority values(status) as statuses\r\n\r\n| eval input_selected=if(trim(\"$selected_host$\")!=\"*\" OR trim(\"$selected_index$\")!=\"*\",1,0)\r\n\r\n| eval value=case(\r\n    input_selected=0, \"select host or index\",\r\n    status_priority=3, \"NO DATA\",\r\n    status_priority=2, \"LATE\",\r\n    status_priority=1, \"OK\",\r\n    true(), \"UNKNOWN\"\r\n)\r\n\r\n| eval percent_label=case(\r\n    input_selected=0, \"select host or index\",\r\n    value=\"OK\", \"logs are arriving within threshold\",\r\n    value=\"LATE\", \"logs are delayed\",\r\n    value=\"NO DATA\", \"no events found\",\r\n    true(), \"unknown source status\"\r\n)\r\n\r\n| table value percent_label",
				"enableSmartSources": true
			},
			"name": "Search_3"
		},
		"ds_L4paPYXc": {
			"type": "ds.chain",
			"options": {
				"extend": "ds_mZZ8Pkmz",
				"query": "| stats count as sources \r\n        count(eval(status=\"OK\")) as ok\r\n        count(eval(status=\"Late\")) as late\r\n        count(eval(status=\"No Data\")) as no_data\r\n  by index\r\n\r\n| eval total=sources\r\n| eval ok_percent=round(ok*100/total,1)\r\n| eval late_percent=round(late*100/total,1)\r\n| eval no_data_percent=round(no_data*100/total,1)\r\n\r\n| table index sources ok late no_data ok_percent late_percent no_data_percent\r\n| sort -no_data -late index"
			},
			"name": "Search_4"
		},
		"ds_wxkQr6yl": {
			"type": "ds.search",
			"options": {
				"query": "| makeresults count=7\r\n| streamstats count as day_num\r\n| eval _time=relative_time(now(), \"-\".(7-day_num).\"d@d\")\r\n| eval events=0\r\n| eval selected=if(trim(\"$selected_host$\")!=\"*\" OR trim(\"$selected_index$\")!=\"*\",1,0)\r\n\r\n| append [\r\n    | tstats count as events\r\n      where index=$selected_index$ host=$selected_host$ earliest=-7d@d latest=now\r\n      by _time span=1d\r\n    | eval selected=if(trim(\"$selected_host$\")!=\"*\" OR trim(\"$selected_index$\")!=\"*\",1,0)\r\n]\r\n\r\n| stats sum(events) as events max(selected) as selected by _time\r\n\r\n| eval events=if(selected=0,0,events)\r\n| eval day=strftime(_time,\"%a %d.%m\")\r\n| sort _time\r\n| table _time day events"
			},
			"name": "ds_base_events_by_day_7d"
		},
		"ds_aW3HA7BE": {
			"type": "ds.chain",
			"options": {
				"query": "| where events_7d>0\r\n| table source sourcetype events_7d latest_event_display percent\r\n| rename\r\n    source as Source\r\n    sourcetype as Sourcetype\r\n    events_7d as \"Events 7 Days\"\r\n    latest_event_display as \"Latest\"\r\n    percent as \"%\"\r\n| sort - \"Events 7 Days\"",
				"extend": "ds_wxkQr6yl"
			},
			"name": "ds_chain_sources_sourcetypes_7d"
		},
		"ds_Oac4EUhw": {
			"type": "ds.chain",
			"options": {
				"query": "| table day events",
				"extend": "ds_wxkQr6yl"
			},
			"name": "Search_5ds_chain_events_by_day_7d"
		}
	},
